"use strict";function numberFormat(number,locale){return Chart.helpers.formatNumber(number,locale)}function preprocessBubbleData(data){const pixelMax=31;const pixelMin=1;const pixelRange=pixelMax-pixelMin;const valueRange=data.datasets[0].data.reduce((acc,val)=>Math.max(acc,val.original??val.r),0);for(const ds of data.datasets){const rawData=ds.rawData||[];const isStructured=Array.isArray(rawData[0]);ds.data.forEach((d,i)=>{const trueR=d.original??d.r;d.original=trueR;const rawR=isStructured?rawData[i]&&rawData[i][2]:rawData[i*3+2];d.originalPrefix=rawR&&rawR.prefix?rawR.prefix:"";d.originalSuffix=rawR&&rawR.suffix?rawR.suffix:"";const percentageRadius=Math.sqrt(Math.abs(trueR)/valueRange);d.r=percentageRadius*pixelRange+pixelMin})}return data}function bubbleChartTooltipLabel(item){const locale=item.chart.options.locale;const lines=[item.dataset.label];if(item.raw?.label){lines.push(item.raw.label)}lines.push(item.chart.data.labels[0]+": "+numberFormat(item.parsed.x,locale),item.chart.data.labels[1]+": "+numberFormat(item.parsed.y,locale),item.chart.data.labels[2]+": "+numberFormat(item.raw.original,locale));return lines}function scatterChartTooltipLabel(item){const locale=item.chart.options.locale;const lines=[item.dataset.label];if(item.raw?.label){lines.push(item.raw.label)}lines.push(item.chart.data.labels[0]+": "+numberFormat(item.parsed.x,locale),item.chart.data.labels[1]+": "+numberFormat(item.parsed.y,locale));return lines}function chartTooltipLabel(item){const type=item.chart.config.type;const labelsPos=item.chart.options.plugins?.["m-chart-helper"]?.labels_pos??"";const locale=item.chart.options.locale;var label=item.dataset.label;if(null==item.raw){return null}if("undefined"==typeof label){label=item.label}if("bar"==type){label=""}if("polarArea"==type){label=item.chart.data.labels[item.dataIndex]}if("both"!=labelsPos){label=""}if("undefined"!=typeof item.dataset.label&&label!=item.dataset.label){label+=item.dataset.label}if(""!=label){label+=": "}var raw=item.dataset.rawData&&item.dataset.rawData[item.dataIndex];var rawValue;if(raw&&null!==raw.value){rawValue=(raw.prefix||"")+numberFormat(raw.value,locale)+(raw.suffix||"")}else if(raw&&raw.text){rawValue=raw.text}else{rawValue=numberFormat(item.raw,locale)}return label+rawValue}const MChartHelper={id:"m-chart-helper",beforeUpdate(chart){const type=chart.config.type;if("bubble"===type){preprocessBubbleData(chart.config.data);chart.options.plugins.tooltip.callbacks={label:item=>bubbleChartTooltipLabel(item)}}else if("scatter"===type){chart.options.plugins.tooltip.callbacks={title:()=>"",label:item=>scatterChartTooltipLabel(item)}}else{chart.options.plugins.tooltip.callbacks={label:item=>chartTooltipLabel(item)}}chart.options.plugins.datalabels.formatter=function(label,context){const locale=chart.options.locale;const rawData=context.dataset.rawData;const dataIndex=context.dataIndex;if(null===label){return label}if("bubble"===type){const prefix=label.originalPrefix||"";const suffix=label.originalSuffix||"";return prefix+numberFormat(label.original,locale)+suffix}if("scatter"===type){const rawEntry=rawData&&rawData[dataIndex];var rawY;if(Array.isArray(rawEntry)){rawY=rawEntry[1]}else{rawY=rawData&&rawData[dataIndex*2+1]}if(rawY&&null!==rawY.value){return(rawY.prefix||"")+numberFormat(rawY.value,locale)+(rawY.suffix||"")}if(rawY&&rawY.text){return rawY.text}return numberFormat(label.y,locale)}var raw=rawData&&rawData[dataIndex];if(raw&&null!==raw.value){return(raw.prefix||"")+numberFormat(raw.value,locale)+(raw.suffix||"")}if(raw&&raw.text){return raw.text}if(Number.isFinite(Number(label))){return numberFormat(label,locale)}return label}}};window.MChartHelper=MChartHelper;